import './PaginationStandard.scss';

import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC } from 'react';
import React, { useEffect, useState } from 'react';

import { classNames } from '../../../helpers/classnames';
import { Icon } from '../../Icon';
import { PaginationCell } from '../PaginationCell';
import type { PaginationStandardProps } from './PaginationStandard.types';

export const PaginationStandard: FC<PaginationStandardProps> = ({ count, onChange, page = 1, className, ...props }) => {
	const [_page, setPage] = useState<number>(page);

	useEffect(() => {
		setPage(page);
	}, [page]);

	const handleCellClick = (cellIndex: number): void => {
		if (cellIndex === _page) {
			return;
		}

		setPage(cellIndex);
		onChange?.(cellIndex);
	};

	const handleLeftClick = (): void => {
		const newIndex = _page - 1;
		if (newIndex >= 1) {
			handleCellClick(newIndex);
		}
		return void 0;
	};

	const handleRightClick = (): void => {
		const newIndex = _page + 1;
		if (newIndex <= count) {
			handleCellClick(newIndex);
		}
		return void 0;
	};

	const navArrowLeft = (
		<li key={0}>
			<PaginationCell
				variant="icon"
				disabled={_page === 1}
				startIcon={<Icon iconName={Icons.NavArrowLeft} size="large" />}
				onClick={handleLeftClick}
				className="dsb_pagination-cell__first"
			/>
		</li>
	);

	const navArrowRight = (
		<li key={count + 1}>
			<PaginationCell
				variant="icon"
				disabled={_page === count}
				startIcon={<Icon iconName={Icons.NavArrowRight} size="large" />}
				onClick={handleRightClick}
			/>
		</li>
	);

	return (
		<ul data-testid="PaginationStandard" className={classNames('dsb_pagination', className)} {...props}>
			{navArrowLeft}
			{[...new Array(count).keys()].map((index: number) => {
				const cellIndex = index + 1;
				return (
					<li key={cellIndex}>
						<PaginationCell
							variant="text"
							active={_page === cellIndex}
							onClick={(): void => {
								handleCellClick(cellIndex);
							}}
						>
							{cellIndex}
						</PaginationCell>
					</li>
				);
			})}
			{navArrowRight}
		</ul>
	);
};
